1	/**
2	 * RunOrchestrator — CLI-free execution engine for sequant workflows.
3	 *
4	 * Owns the full lifecycle: config → issue discovery → dispatch → results.
5	 * Importable and usable without Commander.js or CLI context.
6	 *
7	 * @module
8	 */
9	
10	import chalk from "chalk";
11	import { spawnSync } from "child_process";
12	import pLimit from "p-limit";
13	import type {
14	  ExecutionConfig,
15	  IssueResult,
16	  RunOptions,
17	  BatchExecutionContext,
18	  IssueExecutionContext,
19	  ProgressCallback,
20	} from "./types.js";
21	import type { WorktreeInfo } from "./worktree-manager.js";
22	import {
23	  detectDefaultBranch,
24	  ensureWorktrees,
25	  ensureWorktreesChain,
26	  getWorktreeDiffStats,
27	} from "./worktree-manager.js";
28	import { LogWriter } from "./log-writer.js";
29	import type { RunConfig } from "./run-log-schema.js";
30	import { StateManager } from "./state-manager.js";
31	import { ShutdownManager } from "../shutdown.js";
32	import {
33	  getIssueInfo,
34	  sortByDependencies,
35	  parseBatches,
36	  runIssueWithLogging,
37	} from "./batch-executor.js";
38	import { reconcileStateAtStartup } from "./state-utils.js";
39	import { getCommitHash } from "./git-diff-utils.js";
40	import { MetricsWriter } from "./metrics-writer.js";
41	import { type MetricPhase, determineOutcome } from "./metrics-schema.js";
42	import { getTokenUsageForRun } from "./token-utils.js";
43	import type { SequantSettings } from "../settings.js";
44	import { resolveRunOptions, buildExecutionConfig } from "./config-resolver.js";
45	
46	// ── Public types ────────────────────────────────────────────────────────────
47	
48	/**
49	 * Injectable services for RunOrchestrator.
50	 * All optional — orchestrator degrades gracefully when services are absent.
51	 */
52	export interface OrchestratorServices {
53	  logWriter?: LogWriter | null;
54	  stateManager?: StateManager | null;
55	  shutdownManager?: ShutdownManager;
56	}
57	
58	/**
59	 * CLI-free configuration for RunOrchestrator.
60	 * No Commander.js types leak into this interface.
61	 */
62	export interface OrchestratorConfig {
63	  /** Execution settings (phases, timeouts, mode flags) */
64	  config: ExecutionConfig;
65	  /** Merged run options (post-resolution, no raw CLI types) */
66	  options: RunOptions;
67	  /** Issue metadata keyed by issue number */
68	  issueInfoMap: Map<number, { title: string; labels: string[] }>;
69	  /** Worktree paths keyed by issue number */
70	  worktreeMap: Map<number, WorktreeInfo>;
71	  /** Injectable services */
72	  services: OrchestratorServices;
73	  /** Package manager name (e.g. "npm", "pnpm") */
74	  packageManager?: string;
75	  /** Base branch for rebase/PR targets */
76	  baseBranch?: string;
77	  /** Per-phase progress callback (parallel mode) */
78	  onProgress?: ProgressCallback;
79	}
80	
81	/**
82	 * High-level init config for full lifecycle execution.
83	 * Used by RunOrchestrator.run() — the entry point for programmatic callers.
84	 */
85	export interface RunInit {
86	  /** Raw CLI options (pre-merge) */
87	  options: RunOptions;
88	  /** Resolved settings */
89	  settings: SequantSettings;
90	  /** Manifest metadata */
91	  manifest: { stack: string; packageManager: string };
92	  /** Explicit base branch override */
93	  baseBranch?: string;
94	  /** Per-phase progress callback */
95	  onProgress?: ProgressCallback;
96	}
97	
98	/**
99	 * Structured result of a full orchestrator run.
100	 */
101	export interface RunResult {
102	  /** Per-issue results */
103	  results: IssueResult[];
104	  /** Log file path (if logging enabled) */
105	  logPath: string | null;
106	  /** Non-zero if any issue failed */
107	  exitCode: number;
108	  /** Worktree map (for summary display) */
109	  worktreeMap: Map<number, WorktreeInfo>;
110	  /** Issue info map (for summary display) */
111	  issueInfoMap: Map<number, { title: string; labels: string[] }>;
112	  /** Resolved execution config */
113	  config: ExecutionConfig;
114	  /** Resolved merged options */
115	  mergedOptions: RunOptions;
116	  /** Log writer (for reflection access) */
117	  logWriter: LogWriter | null;
118	}
119	
120	// ── Orchestrator ────────────────────────────────────────────────────────────
121	
122	/**
123	 * CLI-free workflow execution engine.
124	 *
125	 * Two usage modes:
126	 * 1. Full lifecycle: `RunOrchestrator.run(init, issueNumbers)` — handles
127	 *    services, worktrees, state guard, execution, and metrics.
128	 * 2. Low-level: `new RunOrchestrator(config).execute(issueNumbers)` — caller
129	 *    manages setup/teardown.
130	 */
131	export class RunOrchestrator {
132	  private readonly cfg: OrchestratorConfig;
133	
134	  constructor(config: OrchestratorConfig) {
135	    this.validate(config);
136	    this.cfg = config;
137	  }
138	
139	  /**
140	   * Full lifecycle execution — the primary entry point for programmatic use.
141	   *
142	   * Handles: config resolution → services setup → state guard →
143	   * issue discovery → worktree creation → execution → metrics → cleanup.
144	   */
145	  static async run(
146	    init: RunInit,
147	    issueArgs: string[],
148	    batches?: number[][] | null,
149	  ): Promise<RunResult> {
150	    const { options, settings, manifest, onProgress } = init;
151	
152	    // ── Config resolution ──────────────────────────────────────────────
153	    const mergedOptions = resolveRunOptions(options, settings);
154	    const baseBranch =
155	      init.baseBranch ??
156	      options.base ??
157	      settings.run.defaultBase ??
158	      detectDefaultBranch(mergedOptions.verbose ?? false);
159	
160	    // ── Parse issues ───────────────────────────────────────────────────
161	    let issueNumbers: number[];
162	    let resolvedBatches: number[][] | null = batches ?? null;
163	
164	    if (
165	      mergedOptions.batch &&
166	      mergedOptions.batch.length > 0 &&
167	      !resolvedBatches
168	    ) {
169	      resolvedBatches = parseBatches(mergedOptions.batch);
170	      issueNumbers = resolvedBatches.flat();
171	    } else if (resolvedBatches) {
172	      issueNumbers = resolvedBatches.flat();
173	    } else {
174	      issueNumbers = issueArgs
175	        .map((i) => parseInt(i, 10))
176	        .filter((n) => !isNaN(n));
177	    }
178	
179	    if (issueNumbers.length === 0) {
180	      return {
181	        results: [],
182	        logPath: null,
183	        exitCode: 0,
184	        worktreeMap: new Map(),
185	        issueInfoMap: new Map(),
186	        config: buildExecutionConfig(mergedOptions, settings, 0),
187	        mergedOptions,
188	        logWriter: null,
189	      };
190	    }
191	
192	    // Sort by dependencies
193	    if (issueNumbers.length > 1 && !resolvedBatches) {
194	      issueNumbers = sortByDependencies(issueNumbers);
195	    }
196	
197	    // ── Build execution config ─────────────────────────────────────────
198	    const config = buildExecutionConfig(
199	      mergedOptions,
200	      settings,
201	      issueNumbers.length,
202	    );
203	
204	    // ── Services setup ─────────────────────────────────────────────────
205	    let logWriter: LogWriter | null = null;
206	    const shouldLog =
207	      !mergedOptions.noLog &&
208	      !config.dryRun &&
209	      (mergedOptions.logJson ?? settings.run.logJson);
210	
211	    if (shouldLog) {
212	      const runConfig: RunConfig = {
213	        phases: config.phases,
214	        sequential: config.sequential,
215	        qualityLoop: config.qualityLoop,
216	        maxIterations: config.maxIterations,
217	        chain: mergedOptions.chain,
218	        qaGate: mergedOptions.qaGate,
219	      };
220	      try {
221	        logWriter = new LogWriter({
222	          logPath: mergedOptions.logPath ?? settings.run.logPath,
223	          verbose: config.verbose,
224	          startCommit: getCommitHash(process.cwd()),
225	        });
226	        await logWriter.initialize(runConfig);
227	      } catch (err) {
228	        const msg = err instanceof Error ? err.message : String(err);
229	        console.log(
230	          chalk.yellow(
231	            `  ! Log initialization failed, continuing without logging: ${msg}`,
232	          ),
233	        );
234	        logWriter = null;
235	      }
236	    }
237	
238	    let stateManager: StateManager | null = null;
239	    if (!config.dryRun) {
240	      stateManager = new StateManager({ verbose: config.verbose });
241	    }
242	
243	    const shutdown = new ShutdownManager();
244	    if (logWriter) {
245	      const writer = logWriter;
246	      shutdown.registerCleanup("Finalize run logs", async () => {
247	        await writer.finalize();
248	      });
249	    }
250	
251	    // ── Pre-flight state guard ─────────────────────────────────────────
252	    if (stateManager && !config.dryRun) {
253	      try {
254	        const reconcileResult = await reconcileStateAtStartup({
255	          verbose: config.verbose,
256	        });
257	        if (reconcileResult.success && reconcileResult.advanced.length > 0) {
258	          console.log(
259	            chalk.gray(
260	              `  State reconciled: ${reconcileResult.advanced.map((n) => `#${n}`).join(", ")} → merged`,
261	            ),
262	          );
263	        }
264	      } catch (error) {
265	        logNonFatalWarning(
266	          "  !  State reconciliation failed, continuing...",
267	          error,
268	          config.verbose,
269	        );
270	      }
271	    }
272	
273	    if (stateManager && !config.dryRun && !mergedOptions.force) {
274	      const activeIssues: number[] = [];
275	      for (const issueNumber of issueNumbers) {
276	        try {
277	          const issueState = await stateManager.getIssueState(issueNumber);
278	          if (
279	            issueState &&
280	            (issueState.status === "ready_for_merge" ||
281	              issueState.status === "merged")
282	          ) {
283	            console.log(
284	              chalk.yellow(
285	                `  !  #${issueNumber}: already ${issueState.status} — skipping (use --force to re-run)`,
286	              ),
287	            );
288	          } else {
289	            activeIssues.push(issueNumber);
290	          }
291	        } catch (error) {
292	          logNonFatalWarning(
293	            `  !  State lookup failed for #${issueNumber}, including anyway...`,
294	            error,
295	            config.verbose,
296	          );
297	          activeIssues.push(issueNumber);
298	        }
299	      }
300	      if (activeIssues.length < issueNumbers.length) {
301	        issueNumbers = activeIssues;
302	        if (issueNumbers.length === 0) {
303	          console.log(
304	            chalk.yellow(
305	              `\n  All issues already completed. Use --force to re-run.`,
306	            ),
307	          );
308	          shutdown.dispose();
309	          return {
310	            results: [],
311	            logPath: null,
312	            exitCode: 0,
313	            worktreeMap: new Map(),
314	            issueInfoMap: new Map(),
315	            config,
316	            mergedOptions,
317	            logWriter: null,
318	          };
319	        }
320	      }
321	    }
322	
323	    // ── Issue info + worktree setup ────────────────────────────────────
324	    const issueInfoMap = new Map<number, { title: string; labels: string[] }>();
325	    for (const issueNumber of issueNumbers) {
326	      issueInfoMap.set(issueNumber, await getIssueInfo(issueNumber));
327	    }
328	
329	    const useWorktreeIsolation =
330	      mergedOptions.worktreeIsolation !== false && issueNumbers.length > 0;
331	
332	    let worktreeMap: Map<number, WorktreeInfo> = new Map();
333	    if (useWorktreeIsolation && !config.dryRun) {
334	      const issueData = issueNumbers.map((num) => ({
335	        number: num,
336	        title: issueInfoMap.get(num)?.title || `Issue #${num}`,
337	      }));
338	      if (mergedOptions.chain) {
339	        worktreeMap = await ensureWorktreesChain(
340	          issueData,
341	          config.verbose,
342	          manifest.packageManager,
343	          baseBranch,
344	        );
345	      } else {
346	        worktreeMap = await ensureWorktrees(
347	          issueData,
348	          config.verbose,
349	          manifest.packageManager,
350	          baseBranch,
351	        );
352	      }
353	      for (const [issueNum, worktree] of worktreeMap.entries()) {
354	        if (!worktree.existed) {
355	          shutdown.registerCleanup(
356	            `Cleanup worktree for #${issueNum}`,
357	            async () => {
358	              spawnSync(
359	                "git",
360	                ["worktree", "remove", "--force", worktree.path],
361	                {
362	                  stdio: "pipe",
363	                },
364	              );
365	            },
366	          );
367	        }
368	      }
369	    }
370	
371	    // ── Execute ────────────────────────────────────────────────────────
372	    let results: IssueResult[] = [];
373	
374	    try {
375	      const orchestrator = new RunOrchestrator({
376	        config,
377	        options: mergedOptions,
378	        issueInfoMap,
379	        worktreeMap,
380	        services: { logWriter, stateManager, shutdownManager: shutdown },
381	        packageManager: manifest.packageManager,
382	        baseBranch,
383	        onProgress,
384	      });
385	
386	      if (resolvedBatches) {
387	        for (let batchIdx = 0; batchIdx < resolvedBatches.length; batchIdx++) {
388	          const batch = resolvedBatches[batchIdx];
389	          console.log(
390	            chalk.blue(
391	              `\n  Batch ${batchIdx + 1}/${resolvedBatches.length}: Issues ${batch.map((n) => `#${n}`).join(", ")}`,
392	            ),
393	          );
394	          const batchResults = await orchestrator.execute(batch);
395	          results.push(...batchResults);
396	          const batchFailed = batchResults.some((r) => !r.success);
397	          if (batchFailed && config.sequential) {
398	            console.log(
399	              chalk.yellow(
400	                `\n  !  Batch ${batchIdx + 1} failed, stopping batch execution`,
401	              ),
402	            );
403	            break;
404	          }
405	        }
406	      } else {
407	        results = await orchestrator.execute(issueNumbers);
408	      }
409	
410	      // ── Finalize logs ──────────────────────────────────────────────
411	      let logPath: string | null = null;
412	      if (logWriter) {
413	        logPath = await logWriter.finalize({
414	          endCommit: getCommitHash(process.cwd()),
415	        });
416	      }
417	
418	      // ── Record metrics ─────────────────────────────────────────────
419	      if (!config.dryRun && results.length > 0) {
420	        try {
421	          await RunOrchestrator.recordMetrics(
422	            config,
423	            mergedOptions,
424	            results,
425	            worktreeMap,
426	            issueNumbers,
427	          );
428	        } catch (metricsError) {
429	          logNonFatalWarning(
430	            "  !  Metrics recording failed, continuing...",
431	            metricsError,
432	            config.verbose,
433	          );
434	        }
435	      }
436	
437	      return {
438	        results,
439	        logPath,
440	        exitCode: results.some((r) => !r.success) && !config.dryRun ? 1 : 0,
441	        worktreeMap,
442	        issueInfoMap,
443	        config,
444	        mergedOptions,
445	        logWriter,
446	      };
447	    } finally {
448	      shutdown.dispose();
449	    }
450	  }
451	
452	  /**
453	   * Execute workflow for the given issue numbers.
454	   * Returns one IssueResult per issue.
455	   */
456	  async execute(issueNumbers: number[]): Promise<IssueResult[]> {
457	    if (issueNumbers.length === 0) {
458	      return [];
459	    }
460	
461	    const batchCtx = this.buildBatchContext();
462	    const { config } = this.cfg;
463	    const options = this.cfg.options;
464	
465	    // Chain mode implies sequential
466	    if (options.chain) {
467	      config.sequential = true;
468	    }
469	
470	    if (config.sequential) {
471	      return this.executeSequential(issueNumbers, batchCtx, options);
472	    }
473	
474	    return this.executeParallel(issueNumbers, batchCtx);
475	  }
476	
477	  // ── Private helpers ─────────────────────────────────────────────────────
478	
479	  private validate(config: OrchestratorConfig): void {
480	    if (!config.config) {
481	      throw new Error("OrchestratorConfig.config is required");
482	    }
483	    if (
484	      !config.config.phases ||
485	      !Array.isArray(config.config.phases) ||
486	      config.config.phases.length === 0
487	    ) {
488	      throw new Error(
489	        "OrchestratorConfig.config.phases must be a non-empty array",
490	      );
491	    }
492	  }
493	
494	  private buildBatchContext(): BatchExecutionContext {
495	    const { config, options, issueInfoMap, worktreeMap, services } = this.cfg;
496	    return {
497	      config,
498	      options,
499	      issueInfoMap,
500	      worktreeMap,
501	      logWriter: services.logWriter ?? null,
502	      stateManager: services.stateManager ?? null,
503	      shutdownManager: services.shutdownManager,
504	      packageManager: this.cfg.packageManager,
505	      baseBranch: this.cfg.baseBranch,
506	      onProgress: this.cfg.onProgress,
507	    };
508	  }
509	
510	  private async executeSequential(
511	    issueNumbers: number[],
512	    batchCtx: BatchExecutionContext,
513	    options: RunOptions,
514	  ): Promise<IssueResult[]> {
515	    const results: IssueResult[] = [];
516	    const shutdown = this.cfg.services.shutdownManager;
517	
518	    for (let i = 0; i < issueNumbers.length; i++) {
519	      const issueNumber = issueNumbers[i];
520	
521	      if (shutdown?.shuttingDown) {
522	        break;
523	      }
524	
525	      const result = await this.executeOneIssue({
526	        issueNumber,
527	        batchCtx,
528	        chain: options.chain
529	          ? { enabled: true, isLast: i === issueNumbers.length - 1 }
530	          : undefined,
531	      });
532	      results.push(result);
533	
534	      if (!result.success) {
535	        if (options.qaGate && options.chain) {
536	          const qaFailed = result.phaseResults.some(
537	            (p) => p.phase === "qa" && !p.success,
538	          );
539	          if (qaFailed) break;
540	        }
541	        break;
542	      }
543	    }
544	
545	    return results;
546	  }
547	
548	  private async executeParallel(
549	    issueNumbers: number[],
550	    batchCtx: BatchExecutionContext,
551	  ): Promise<IssueResult[]> {
552	    const limit = pLimit(this.cfg.config.concurrency);
553	    const shutdown = this.cfg.services.shutdownManager;
554	
555	    const settledResults = await Promise.allSettled(
556	      issueNumbers.map((issueNumber) =>
557	        limit(async () => {
558	          if (shutdown?.shuttingDown) {
559	            return {
560	              issueNumber,
561	              success: false,
562	              phaseResults: [],
563	              durationSeconds: 0,
564	              loopTriggered: false,
565	            } as IssueResult;
566	          }
567	
568	          return this.executeOneIssue({
569	            issueNumber,
570	            batchCtx: { ...batchCtx, onProgress: this.cfg.onProgress },
571	            parallelIssueNumber: issueNumber,
572	          });
573	        }),
574	      ),
575	    );
576	
577	    return settledResults.map((settled, i) => {
578	      if (settled.status === "fulfilled") {
579	        return settled.value;
580	      }
581	      return {
582	        issueNumber: issueNumbers[i],
583	        success: false,
584	        phaseResults: [],
585	        durationSeconds: 0,
586	        loopTriggered: false,
587	      } as IssueResult;
588	    });
589	  }
590	
591	  private async executeOneIssue(args: {
592	    issueNumber: number;
593	    batchCtx: BatchExecutionContext;
594	    chain?: { enabled: boolean; isLast: boolean };
595	    parallelIssueNumber?: number;
596	  }): Promise<IssueResult> {
597	    const { issueNumber, batchCtx, chain, parallelIssueNumber } = args;
598	    const {
599	      config,
600	      options,
601	      issueInfoMap,
602	      worktreeMap,
603	      logWriter,
604	      stateManager,
605	      shutdownManager,
606	      packageManager,
607	      baseBranch,
608	      onProgress,
609	    } = batchCtx;
610	
611	    const issueInfo = issueInfoMap.get(issueNumber) ?? {
612	      title: `Issue #${issueNumber}`,
613	      labels: [],
614	    };
615	    const worktreeInfo = worktreeMap.get(issueNumber);
616	
617	    if (logWriter) {
618	      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
619	    }
620	
621	    const ctx: IssueExecutionContext = {
622	      issueNumber,
623	      title: issueInfo.title,
624	      labels: issueInfo.labels,
625	      config,
626	      options,
627	      services: { logWriter, stateManager, shutdownManager },
628	      worktree: worktreeInfo
629	        ? { path: worktreeInfo.path, branch: worktreeInfo.branch }
630	        : undefined,
631	      chain,
632	      packageManager,
633	      baseBranch,
634	      onProgress,
635	    };
636	    const result = await runIssueWithLogging(ctx);
637	
638	    if (logWriter && result.prNumber && result.prUrl) {
639	      logWriter.setPRInfo(result.prNumber, result.prUrl, parallelIssueNumber);
640	    }
641	    if (logWriter) {
642	      logWriter.completeIssue(parallelIssueNumber);
643	    }
644	
645	    return result;
646	  }
647	
648	  private static async recordMetrics(
649	    config: ExecutionConfig,
650	    mergedOptions: RunOptions,
651	    results: IssueResult[],
652	    worktreeMap: Map<number, WorktreeInfo>,
653	    issueNumbers: number[],
654	  ): Promise<void> {
655	    const metricsWriter = new MetricsWriter({ verbose: config.verbose });
656	    const totalDuration = results.reduce(
657	      (sum, r) => sum + (r.durationSeconds ?? 0),
658	      0,
659	    );
660	    const allPhases = new Set<MetricPhase>();
661	    for (const result of results) {
662	      for (const pr of result.phaseResults) {
663	        const phase = pr.phase as MetricPhase;
664	        if (
665	          [
666	            "spec",
667	            "security-review",
668	            "testgen",
669	            "exec",
670	            "test",
671	            "qa",
672	            "loop",
673	          ].includes(phase)
674	        ) {
675	          allPhases.add(phase);
676	        }
677	      }
678	    }
679	    let totalFilesChanged = 0;
680	    let totalLinesAdded = 0;
681	    let totalQaIterations = 0;
682	    for (const result of results) {
683	      const wt = worktreeMap.get(result.issueNumber);
684	      if (wt?.path) {
685	        const s = getWorktreeDiffStats(wt.path);
686	        totalFilesChanged += s.filesChanged;
687	        totalLinesAdded += s.linesAdded;
688	      }
689	      if (result.loopTriggered) {
690	        totalQaIterations += result.phaseResults.filter(
691	          (p) => p.phase === "loop",
692	        ).length;
693	      }
694	    }
695	    const cliFlags: string[] = [];
696	    if (mergedOptions.sequential) cliFlags.push("--sequential");
697	    if (mergedOptions.chain) cliFlags.push("--chain");
698	    if (mergedOptions.qaGate) cliFlags.push("--qa-gate");
699	    if (mergedOptions.qualityLoop) cliFlags.push("--quality-loop");
700	    if (mergedOptions.testgen) cliFlags.push("--testgen");
701	    const tokenUsage = getTokenUsageForRun(undefined, true);
702	    const passed = results.filter((r) => r.success).length;
703	    await metricsWriter.recordRun({
704	      issues: issueNumbers,
705	      phases: Array.from(allPhases),
706	      outcome: determineOutcome(passed, results.length),
707	      duration: totalDuration,
708	      model: process.env.ANTHROPIC_MODEL ?? "opus",
709	      flags: cliFlags,
710	      metrics: {
711	        tokensUsed: tokenUsage.tokensUsed,
712	        filesChanged: totalFilesChanged,
713	        linesAdded: totalLinesAdded,
714	        acceptanceCriteria: 0,
715	        qaIterations: totalQaIterations,
716	        inputTokens: tokenUsage.inputTokens || undefined,
717	        outputTokens: tokenUsage.outputTokens || undefined,
718	        cacheTokens: tokenUsage.cacheTokens || undefined,
719	      },
720	    });
721	    if (config.verbose) {
722	      console.log(chalk.gray("  Metrics recorded to .sequant/metrics.json"));
723	    }
724	  }
725	}
726	
727	/** Log a non-fatal warning: one-line summary always, detail in verbose. */
728	export function logNonFatalWarning(
729	  message: string,
730	  error: unknown,
731	  verbose: boolean,
732	): void {
733	  console.log(chalk.yellow(message));
734	  if (verbose) {
735	    console.log(chalk.gray(`    ${error}`));
736	  }
737	}
